import React from 'react';
import { Carousel } from './Carousel';
import type { Slide } from './Carousel';

const SLIDES: Slide[] = [
  { id: '1', content: '🏔️ Mountain Vista' },
  { id: '2', content: '🌊 Ocean Breeze' },
  { id: '3', content: '🌲 Forest Trail' },
  { id: '4', content: '🏜️ Desert Sunset' },
  { id: '5', content: '❄️ Arctic Aurora' },
];

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Infinite Carousel</h1>
      <Carousel slides={SLIDES} autoPlay interval={3000} />
    </div>
  );
}

import React, { useState } from 'react';
import './styles.css';

export interface Slide {
  id: string;
  content: string;
}

interface CarouselProps {
  slides: Slide[];
  autoPlay?: boolean;
  interval?: number;
}

export const Carousel: React.FC<CarouselProps> = ({
  slides,
  autoPlay = false,
  interval = 3000,
}) => {
  const [current, setCurrent] = useState(0);

  // TODO: Implement next/prev with wrapping
  // TODO: Implement auto-play with useEffect + setInterval
  // TODO: Pause auto-play on hover

  return (
    <div data-testid="carousel" className="carousel">
      <div data-testid="carousel-slide" className="carousel__slide">
        {slides[current]?.content}
      </div>

      <button data-testid="carousel-prev" className="carousel__btn carousel__btn--prev">
        &#8249;
      </button>
      <button data-testid="carousel-next" className="carousel__btn carousel__btn--next">
        &#8250;
      </button>

      <div className="carousel__dots">
        {slides.map((_, i) => (
          <button
            key={i}
            data-testid={`carousel-dot-${i}`}
            className={`carousel__dot${i === current ? ' carousel__dot--active' : ''}`}
          />
        ))}
      </div>

      <div data-testid="carousel-counter" className="carousel__counter">
        {current + 1} / {slides.length}
      </div>
    </div>
  );
};

export default Carousel;

.carousel {
  position: relative;
  max-width: 32rem;
  background: #1f2937;
  border-radius: 0.75rem;
  overflow: hidden;
  user-select: none;
}

.carousel__slide {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 16rem;
  font-size: 2rem;
  color: white;
  transition: opacity 0.3s ease;
}

.carousel__btn {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  background: rgba(255, 255, 255, 0.15);
  border: none;
  color: white;
  font-size: 2rem;
  width: 2.5rem;
  height: 2.5rem;
  border-radius: 9999px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.15s ease;
}

.carousel__btn:hover {
  background: rgba(255, 255, 255, 0.3);
}

.carousel__btn--prev { left: 0.75rem; }
.carousel__btn--next { right: 0.75rem; }

.carousel__dots {
  display: flex;
  justify-content: center;
  gap: 0.375rem;
  padding: 0.75rem 0;
}

.carousel__dot {
  width: 0.5rem;
  height: 0.5rem;
  border-radius: 9999px;
  border: none;
  background: rgba(255, 255, 255, 0.35);
  cursor: pointer;
  padding: 0;
  transition: all 0.2s ease;
}

.carousel__dot--active {
  background: white;
  transform: scale(1.3);
}

.carousel__counter {
  text-align: center;
  font-size: 0.75rem;
  color: rgba(255, 255, 255, 0.6);
  padding-bottom: 0.75rem;
  font-variant-numeric: tabular-nums;
}

