import { render, screen, fireEvent, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import { Carousel } from './Carousel';

const SLIDES = [
  { id: '1', content: 'Slide A' },
  { id: '2', content: 'Slide B' },
  { id: '3', content: 'Slide C' },
];

describe('Carousel', () => {
  beforeEach(() => jest.useFakeTimers());
  afterEach(() => jest.useRealTimers());

  it('renders the first slide initially', () => {
    render(<Carousel slides={SLIDES} />);
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide A');
    expect(screen.getByTestId('carousel-counter')).toHaveTextContent('1 / 3');
  });

  it('navigates to next slide', () => {
    render(<Carousel slides={SLIDES} />);
    fireEvent.click(screen.getByTestId('carousel-next'));
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide B');
  });

  it('navigates to previous slide', () => {
    render(<Carousel slides={SLIDES} />);
    fireEvent.click(screen.getByTestId('carousel-next'));
    fireEvent.click(screen.getByTestId('carousel-prev'));
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide A');
  });

  it('wraps to first slide when clicking Next on last', () => {
    render(<Carousel slides={SLIDES} />);
    fireEvent.click(screen.getByTestId('carousel-next'));
    fireEvent.click(screen.getByTestId('carousel-next'));
    fireEvent.click(screen.getByTestId('carousel-next'));
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide A');
    expect(screen.getByTestId('carousel-counter')).toHaveTextContent('1 / 3');
  });

  it('wraps to last slide when clicking Prev on first', () => {
    render(<Carousel slides={SLIDES} />);
    fireEvent.click(screen.getByTestId('carousel-prev'));
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide C');
  });

  it('navigates to slide when dot is clicked', () => {
    render(<Carousel slides={SLIDES} />);
    fireEvent.click(screen.getByTestId('carousel-dot-2'));
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide C');
    expect(screen.getByTestId('carousel-dot-2')).toHaveClass('carousel__dot--active');
  });

  it('auto-advances when autoPlay is true', () => {
    render(<Carousel slides={SLIDES} autoPlay interval={1000} />);
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide A');
    act(() => jest.advanceTimersByTime(1000));
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide B');
    act(() => jest.advanceTimersByTime(1000));
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide C');
  });

  it('pauses auto-play on hover', () => {
    render(<Carousel slides={SLIDES} autoPlay interval={1000} />);
    fireEvent.mouseEnter(screen.getByTestId('carousel'));
    act(() => jest.advanceTimersByTime(3000));
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide A');
    fireEvent.mouseLeave(screen.getByTestId('carousel'));
    act(() => jest.advanceTimersByTime(1000));
    expect(screen.getByTestId('carousel-slide')).toHaveTextContent('Slide B');
  });
});

